import { useEffect, useLayoutEffect, useRef, useState } from "react";
import { viewModeStore } from "./hooks/useViewMode";
import "./App.css";
import PathConfig from "./components/PathMenu/PathConfig";
import PathSimulator from "./components/PathSimulator";
import ControlConfig from "./components/ControlConfig";
import Config from "./components/Config/Config";
import { clamp, FIELD_IMG_DIMENSIONS } from "./core/Util";
import Field from "./components/Field/Field";
import { ScaleContext } from "./contexts/ScaleContext";
import { fileFormatStore } from "./hooks/useFileFormat";
import { useFieldImg } from "./hooks/useFieldImg";
import HoverButton from "./components/Util/HoverButton";
import threeDots from "./assets/three-dots.svg";
import lines from "./assets/lines.svg";
import marker from "./assets/marker.svg";
import homeButton from "./assets/home.svg";

export default function App() {
  const pathName = fileFormatStore.useSelector(s => s.path.name);

  useEffect(() => {
    document.title = pathName || "mikGen";
  }, [pathName]);

  const viewportRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const fieldRef = useRef<HTMLDivElement>(null);
  const rightPanelRef = useRef<HTMLDivElement>(null);
  const cachedFieldW = useRef(0);
  const cachedRightW = useRef(0);

  const [img, setImg] = useFieldImg();
  const isFieldPanned = img.x !== 0 || img.y !== 0 || img.w !== FIELD_IMG_DIMENSIONS.w || img.h !== FIELD_IMG_DIMENSIONS.h;

  const [scale, setScale] = useState(1);
  const [showConfig, setShowConfig] = useState(true);
  const [showRightPanel, setShowRightPanel] = useState(true);
  const [canvasWidth, setCanvasWidth] = useState(FIELD_IMG_DIMENSIONS.w);
  const fullyCollapsed = !showConfig && !showRightPanel;
  const [configPopout, setConfigPopout] = useState(false);
  const [pathConfigPopout, setPathConfigPopout] = useState(false);
  const [controlConfigPopout, setControlConfigPopout] = useState(false);
  const computeRef = useRef<() => void>(() => {});

  useEffect(() => {
    if (showConfig) setConfigPopout(false);
  }, [showConfig]);

  useEffect(() => {
    if (showRightPanel) { setPathConfigPopout(false); setControlConfigPopout(false); }
  }, [showRightPanel]);

  useLayoutEffect(() => {
    const viewport = viewportRef.current;
    const content = contentRef.current;
    if (!viewport || !content) return;

    const compute = () => {
      const mode = viewModeStore.getState();
      const prev = content.style.transform;
      content.style.transform = "scale(1)";

      const vw = viewport.clientWidth;
      const vh = viewport.clientHeight;

      const fw = fieldRef.current?.scrollWidth ?? 0;
      const rw = rightPanelRef.current?.scrollWidth ?? 0;
      if (fw > 0) cachedFieldW.current = fw;
      if (rw > 0) cachedRightW.current = rw;

      const autoConfig = vw - 16 > cachedFieldW.current + cachedRightW.current;
      const autoRight = vw - 16 > cachedFieldW.current + 250;
      const nextShowConfig = mode === "standard" ? true : (mode === "collapsed-config" || mode === "fully-collapsed" ? false : autoConfig);
      const nextShowRight = mode === "standard" ? true : (mode === "collapsed-list" || mode === "fully-collapsed" ? false : autoRight);
      setShowConfig(nextShowConfig);
      setShowRightPanel(nextShowRight);

      const cw = content.scrollWidth;
      const ch = content.scrollHeight;

      content.style.transform = prev;

      if (cw <= 0 || ch <= 0) return;

      const padding = 16;
      const CONFIG_W = 196;
      const fullyCollapsedNext = !nextShowConfig && !nextShowRight;

      if (fullyCollapsedNext) {
        const s = clamp((vh - padding) / ch, 0.75, 2);
        setScale(s);
        setCanvasWidth(Math.round(vw / s));
      } else {
        const totalCw = (nextShowConfig ? CONFIG_W : 0) + cw;
        setScale(clamp(Math.min((vw - padding) / totalCw, (vh - padding) / ch), 0.75, 2));
        setCanvasWidth(FIELD_IMG_DIMENSIONS.w);
      }
    };

    computeRef.current = compute;
    compute();

    const ro = new ResizeObserver(compute);
    ro.observe(viewport);
    ro.observe(content);

    window.addEventListener("resize", compute);
    return () => {
      ro.disconnect();
      window.removeEventListener("resize", compute);
    };
  }, []);

  useEffect(() => {
    return viewModeStore.subscribe(() => computeRef.current());
  }, []);

  return (
    <ScaleContext.Provider value={scale}>
      <div ref={viewportRef} className={`w-screen h-screen overflow-hidden${fullyCollapsed ? " flex items-center justify-center" : ""}`}>

        <HoverButton
          src={threeDots}
          onClick={() => setConfigPopout(v => !v)}
          className={`fixed top-[10px] left-[10px] z-50 w-[33px] h-[33px]${showConfig ? " hidden" : ""}`}
          imgClassName="w-5 h-5"
        />
        <div
          className="fixed flex flex-col"
          style={
            !showConfig && !configPopout
              ? { display: "none" }
              : showConfig
              ? { top: "10px", left: "10px", transform: `scale(${scale})`, transformOrigin: "top left", zIndex: 10 }
              : { top: "52px", left: "10px", transform: "scale(0.85)", transformOrigin: "top left", height: "calc((100vh - 62px) / 0.85)", zIndex: 50 }
          }
        >
          <Config fillHeight={!showConfig} />
        </div>

        {!showRightPanel && (
          <>
            <HoverButton
              src={lines}
              onClick={() => setPathConfigPopout(v => !v)}
              className="fixed top-[10px] right-[10px] z-50 w-[33px] h-[33px]"
              imgClassName="w-5 h-5"
            />
            <HoverButton
              src={marker}
              onClick={() => setControlConfigPopout(v => !v)}
              className="fixed top-[50px] right-[10px] z-50 w-[33px] h-[33px]"
              imgClassName="w-5 h-5"
            />
            {isFieldPanned && (
              <HoverButton
                src={homeButton}
                onClick={() => setImg(FIELD_IMG_DIMENSIONS)}
                className="fixed top-[90px] right-[10px] z-50 w-[33px] h-[33px]"
                imgClassName="w-5 h-5"
              />
            )}
            <div
              className="fixed right-[10px] z-50 flex flex-col gap-2"
              style={{ top: isFieldPanned ? "130px" : "97px", transform: "scale(0.85)", transformOrigin: "top right" }}
            >
              <div className={pathConfigPopout ? "" : "hidden"}>
                <PathConfig />
              </div>
              <div className={controlConfigPopout ? "" : "hidden"}>
                <ControlConfig />
              </div>
            </div>
          </>
        )}
        <div
          ref={contentRef}
          style={{ transform: `scale(${scale})`, transformOrigin: fullyCollapsed ? "center" : "top left", marginLeft: showConfig ? `${10 + 196 * scale}px` : undefined }}
          className="inline-flex w-max h-max"
        >
          <div className="inline-flex">
            <div ref={fieldRef} className={`flex flex-col gap-[10px] ml-[4px] pt-[10px]${fullyCollapsed ? " items-center" : ""}`}>
              <Field showRightPanel={showRightPanel} canvasWidth={canvasWidth} />
              <PathSimulator />
            </div>
            {showRightPanel && (
              <div ref={rightPanelRef} className="flex flex-col gap-[10px] pt-[10px] pl-[10px]">
                <PathConfig />
                <ControlConfig />
              </div>
            )}
          </div>
        </div>
      </div>
    </ScaleContext.Provider>
  );
}
